INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 155, 27, "A", 44, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 16, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2, 100101, "ヒヨリ", "東山奈央", "獣人族", "人助け、応援", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 158, 5, "O", 47, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2, 100201, "ユイ", "種田梨沙", "ヒューマン", "料理、人間観察", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 12, "B", 46, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2, 100301, "レイ", "早見沙織", "魔族", "読書、乗馬、お茶", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 128, 10, "O", 27, "リトルリリカル", "探検好きのイタズラっ子", 9, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 5, 100401, "ミソギ", "諸星すみれ", "ヒューマン", "いたずら、探検", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 146, 25, "O", 40, "王宮騎士団（NIGHTMARE）", "ヒーローに憧れる騎士見習いの少女", 12, "？？？", 8, 100501, "マツリ", "下田麻美", "獣人族", "ヒーローごっこ", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 150, 22, "O", 42, "悪魔偽王国軍（ディアボロス）", "甘え上手なみんなの人気者", 13, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 7, 100601, "アカリ", "浅倉杏美", "魔族", "サックス", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 130, 23, "B", 32, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 14, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7, 100701, "ミヤコ", "雨宮天", "魔族", "プリンを食べること", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 150, 10, "AB", 40, "ヴァイスフリューゲル　ランドソル支部", "ボクは誰よりも美しい", 14, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 15, 100801, "ユキ", "大空直美", "エルフ", "鏡で自分を見ること", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 159, 5, "A", 45, "トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", 17, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 13, 100901, "アンナ", "髙野麻美", "魔族", "小説執筆", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 155, 22, "O", 42, "自警団（カォン）", "マホマホ王国のプリンセス", 16, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 10, 101001, "マホ", "内田真礼", "獣人族", "空想、ぬいぐるみ集め", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 156, 25, "A", 44, "ラビリンス", "人懐っこくてマシンガントークな妹系少女", 15, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3, 101101, "リノ", "阿澄佳奈", "ヒューマン", "お裁縫", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 156, 24, "A", 46, "フォレスティエ", "みんなのために超能力を使う眠り姫", 17, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 6, 101201, "ハツネ", "大橋彩香", "エルフ", "妹と遊ぶこと、二度寝、昼寝、早寝", 12);
