INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 167, 10, "O", 48, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", 17, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14, 101601, "スズナ", "上坂すみれ", "魔族", "ファッション", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 158, 7, "A", 53, "自警団（カォン）", "いつでも「なんくるないさ～」な天然娘", 17, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 10, 101701, "カオリ", "高森奈津美", "獣人族", "踊り、空手", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 162, 14, "B", 52, "ルーセント学院", "多くの男性を魅了する無垢な女教師", 23, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14, 101801, "イオ", "伊藤静", "魔族", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 117, 3, "O", 21, "リトルリリカル", "お歌もにんじんも、ウサギさんも大好き♪", 10, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 5, 102001, "ミミ", "日高里菜", "獣人族", "かわいいもの集め", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 150, 9, "B", 40, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 12, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, 102101, "クルミ", "植田佳奈", "ヒューマン", "観劇、おままごと", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 150, 22, "O", 40, "悪魔偽王国軍（ディアボロス）", "人見知りであまのじゃくな女の子", 13, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 7, 102201, "ヨリ", "原紗友里", "魔族", "ゲーム全般", 11);
