INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 154, 12, "O", 43, "サレンディア救護院", "お嬢さまのためにがんばるドジっ娘メイド", 15, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9, 102501, "スズメ", "悠木碧", "ヒューマン", "ご奉仕", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 144, 1, "B", 42, "牧場（エリザベスパーク）", "遊びと睡眠が何より大事なぐうたら娘", 17, "test", 11, 102601, "リン", "小岩井ことり", "獣人族", "あんパン", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 154, 30, "B", 43, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", 16, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13, 102701, "エリコ", "橋本ちなみ", "魔族", "実験、裁縫、料理", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 156, 4, "A", 43, "サレンディア救護院", "救護院を経営する優しい庶民派お嬢様", 17, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9, 102801, "サレン", "堀江由衣", "エルフ", "経営、お茶会", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 157, 24, "B", 40, "カルミナ", "歌って踊れる大人気アイドル", 17, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 4, 102901, "ノゾミ", "日笠陽子", "ヒューマン", "舞台鑑賞、ダンス", 1);
