INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 142, 3, "B", 35, "牧場（エリザベスパーク）", "みんなを笑顔にするお笑い牧場主", 20, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 11, 103301, "マヒル", "新田恵海", "ヒューマン", "漫才", 3);
