INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 168, 9, "O", 54, "自警団（カォン）", "男勝りで情に厚いワイルド娘", 17, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 10, 104301, "マコト", "小松未可子", "獣人族", "お菓子作り", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 172, 5, "A", 50, "悪魔偽王国軍（ディアボロス）", "かつては夜を支配した最強の吸血鬼", "??", "test", 7, 104401, "イリヤ", "丹下桜", "魔族", "世界征服", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 157, 19, "AB", 49, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15, 104501, "クウカ", "長妻樹里", "ヒューマン", "小説を読むこと", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 158, 1, "AB", 48, "メルクリウス財団", "弱きを助け強きをくじく猫娘", 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12, 104601, "タマキ", "沼倉愛美", "獣人族", "猫とたわむれること", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 171, 25, "A", 50, "王宮騎士団（NIGHTMARE）", "素顔を見せない冷静沈着な女性騎士", 25, "？？？", 8, 104701, "ジュン", "川澄綾子", "ヒューマン", "格闘技、湯浴み", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 11, "O", 49, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", 20, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12, 104801, "ミフユ", "田所あずさ", "ヒューマン", "傭兵などのアルバイト", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 168, 24, "O", 54, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3, 104901, "シズル", "生天目仁美", "ヒューマン", "家事全般", 10);
