INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 158, 1, "AB", 48, "メルクリウス財団", "弱きを助け強きをくじく猫娘", 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12, 107901, "タマキ（サマー）", "沼倉愛美", "獣人族", "猫とたわむれること", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 11, "O", 49, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", 20, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12, 108001, "ミフユ（サマー）", "田所あずさ", "ヒューマン", "傭兵などのアルバイト", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 157, 22, "AB", 42, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", 18, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7, 108101, "シノブ（ハロウィン）", "大坪由佳", "魔族", "占い", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 130, 23, "B", 32, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 14, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7, 108201, "ミヤコ（ハロウィン）", "雨宮天", "魔族", "プリンを食べること", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 120, 3, "A", 22, "ルーセント学院", "ちょっとおませな恋に恋する女の子", 11, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14, 108301, "ミサキ（ハロウィン）", "久野美咲", "魔族", "ファッション誌鑑賞、コスメ集め", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 3, "O", 46, "カルミナ", "人々を守るために歌う、唱喚士の少女", 17, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4, 108401, "チカ（クリスマス）", "福原綾香", "ヒューマン", "各種楽器", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 150, 9, "B", 40, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 12, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, 108501, "クルミ（クリスマス）", "植田佳奈", "ヒューマン", "観劇、おままごと", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 148, 10, "B", 38, "サレンディア救護院", "ぷうきちといつも一緒！", 14, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 9, 108601, "アヤネ（クリスマス）", "芹澤優", "ヒューマン", "屋内でできる遊び", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 155, 27, "A", 44, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 16, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2, 108701, "ヒヨリ（ニューイヤー）", "東山奈央", "獣人族", "人助け、応援", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 158, 5, "O", 47, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2, 108801, "ユイ（ニューイヤー）", "種田梨沙", "ヒューマン", "料理、人間観察", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 12, "B", 46, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2, 108901, "レイ（ニューイヤー）", "早見沙織", "魔族", "読書、乗馬、お茶", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 154, 30, "B", 43, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", 16, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13, 109001, "エリコ（バレンタイン）", "橋本ちなみ", "魔族", "実験、裁縫、料理", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 168, 24, "O", 54, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3, 109101, "シズル（バレンタイン）", "生天目仁美", "ヒューマン", "家事全般", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 156, 1, "AB", 55, "？？？", "英霊と契約を結んだマナリアの天才王女", 17, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "", 109201, "アン", "日笠陽子", "ヒューマン", "読書", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 144, 4, "O", 45, "？？？", "マナリア魔法学院の新入生", 16, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "", 109301, "ルゥ", "こやまきみこ", "ヒューマン", "食べること、眠ること", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 167, 3, "B", 67, "？？？", "人を超越した力を有す心優しい竜姫", 17, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "", 109401, "グレア", "福原綾香", "半人半竜", "ピアノ", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 157, 19, "AB", 49, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15, 109501, "クウカ（オーエド）", "長妻樹里", "ヒューマン", "小説を読むこと", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, 163, 31, "O", 51, "ヴァイスフリューゲル　ランドソル支部", "トーゴクの神秘、オシエテクダサイ！", 16, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15, 109601, "ニノン（オーエド）", "佐藤聡美", "ヒューマン", "忍法開発", 8);
